18	
19	// Default 8-item layout matching web-component.html
20	const DEFAULT_ITEMS: ItemRect[] = [
21	  { id: "item-a", column: 1, row: 1, width: 2, height: 1 },
22	  { id: "item-b", column: 3, row: 1, width: 1, height: 1 },
23	  { id: "item-c", column: 4, row: 1, width: 1, height: 1 },
24	  { id: "item-d", column: 1, row: 2, width: 1, height: 2 },
25	  { id: "item-e", column: 2, row: 2, width: 2, height: 1 },
26	  { id: "item-f", column: 4, row: 2, width: 1, height: 1 },
27	  { id: "item-g", column: 2, row: 3, width: 1, height: 1 },
28	  { id: "item-h", column: 3, row: 3, width: 2, height: 1 },
29	];
30	
31	const encoder = new TextEncoder();
32	
33	type Tab = "morph" | "server" | "client";
34	
35	interface StreamWriter {
36	  writer: WritableStreamDefaultWriter;
37	  tab: Tab;
38	}
