40	export class GridSession extends DurableObject {
41	  private sql: SqlStorage;
42	  private streams = new Set<StreamWriter>();
43	
44	  constructor(ctx: DurableObjectState, env: Record<string, unknown>) {
45	    super(ctx, env);
46	    this.sql = ctx.storage.sql;
47	    this.sql.exec(`
48	      CREATE TABLE IF NOT EXISTS items (
49	        id TEXT PRIMARY KEY,
50	        col INTEGER NOT NULL,
51	        row INTEGER NOT NULL,
52	        width INTEGER NOT NULL DEFAULT 1,
53	        height INTEGER NOT NULL DEFAULT 1
54	      )
55	    `);
56	  }
57	
58	  /**
59	   * fetch() handler for the SSE stream endpoint.
60	   * The worker calls stub.fetch() to open a long-lived SSE connection.
61	   * The DO holds the writable side and pushes events on layout changes.
62	   */
63	  async fetch(request: Request): Promise<Response> {
64	    const url = new URL(request.url);
65	    const tab = (url.searchParams.get("tab") || "morph") as Tab;
66	
67	    const { readable, writable } = new TransformStream();
68	    const writer = writable.getWriter();
69	    const stream: StreamWriter = { writer, tab };
70	    this.streams.add(stream);
71	
72	    // Clean up when the client disconnects
73	    writer.closed
74	      .then(() => this.streams.delete(stream))
75	      .catch(() => this.streams.delete(stream));
76	
77	    // Send current layout as the first event (format depends on tab)
78	    const event = this.formatLayoutEvent(this.getLayout(), tab);
79	    if (event) writer.write(encoder.encode(event)).catch(() => {});
80	
81	    return new Response(readable, {
82	      headers: {
83	        "Content-Type": "text/event-stream",
84	        "Cache-Control": "no-cache",
85	      },
86	    });
87	  }
88	
89	  /** Format a layout SSE event for the given tab type. */
90	  private formatLayoutEvent(layout: ItemRect[], tab: Tab): string | null {
91	    switch (tab) {
92	      case "morph":
93	        return patchElements(
94	          `<style id="morph-layout">${layoutToCSS(layout, MORPH_SELECTOR)}</style>`,
95	          { selector: "#morph-layout", mode: "outer", useViewTransition: true },
96	        );
97	      case "server":
98	        return patchSignals({ layoutCSS: layoutToCSS(layout, SERVER_SELECTOR) });
99	      case "client":
100	        return null; // client tab manages layout locally
101	    }
102	  }
103	
104	  /** Broadcast an SSE event to all connected streams. */
105	  private broadcast(event: string): void {
106	    const data = encoder.encode(event);
107	    for (const stream of this.streams) {
108	      stream.writer.write(data).catch(() => this.streams.delete(stream));
109	    }
110	  }
111	
112	  /** Broadcast current layout to all connected clients (each gets its own format). */
113	  private broadcastLayout(layout: ItemRect[]): void {
114	    for (const stream of this.streams) {
115	      const event = this.formatLayoutEvent(layout, stream.tab);
116	      if (event) {
117	        stream.writer.write(encoder.encode(event)).catch(() => this.streams.delete(stream));
118	      }
119	    }
120	  }
121	
122	  private seed(): void {
123	    for (const item of DEFAULT_ITEMS) {
124	      this.sql.exec(
125	        `INSERT OR REPLACE INTO items (id, col, row, width, height) VALUES (?, ?, ?, ?, ?)`,
126	        item.id,
127	        item.column,
128	        item.row,
129	        item.width,
130	        item.height,
131	      );
132	    }
133	  }
134	
135	  getLayout(): ItemRect[] {
136	    const rows = this.sql.exec("SELECT id, col, row, width, height FROM items").toArray();
137	    if (rows.length === 0) {
138	      this.seed();
139	      return [...DEFAULT_ITEMS];
140	    }
141	    return rows.map((r) => ({
142	      id: r.id as string,
143	      column: r.col as number,
144	      row: r.row as number,
145	      width: r.width as number,
146	      height: r.height as number,
147	    }));
148	  }
149	
150	  applyMove(itemId: string, targetCol: number, targetRow: number, persist: boolean): void {
151	    const items = this.getLayout();
152	    const target: GridCell = { column: targetCol, row: targetRow };
153	    const layout = calculateLayout(items, itemId, target);
154	    if (persist) this.persistLayout(layout);
155	    this.broadcastLayout(layout);
156	  }
157	
158	  applyResize(
159	    itemId: string,
160	    col: number,
161	    row: number,
162	    width: number,
163	    height: number,
164	    persist: boolean,
165	  ): void {
166	    const items = this.getLayout();
167	    const resized = items.find((i) => i.id === itemId);
168	    if (resized) {
169	      resized.column = col;
170	      resized.row = row;
171	      resized.width = width;
172	      resized.height = height;
173	    }
174	    const target: GridCell = { column: col, row: row };
175	    const layout = calculateLayout(items, itemId, target);
176	    const item = layout.find((i) => i.id === itemId);
177	    if (item) {
178	      item.width = width;
179	      item.height = height;
180	    }
181	    if (persist) this.persistLayout(layout);
182	    this.broadcastLayout(layout);
183	  }
184	
185	  saveLayout(items: ItemRect[]): void {
186	    this.persistLayout(items);
187	    this.broadcast(patchSignals({ saved: true, savedAt: new Date().toLocaleTimeString() }));
188	  }
189	
190	  reset(): void {
191	    this.sql.exec("DELETE FROM items");
192	    this.seed();
193	    this.broadcastLayout([...DEFAULT_ITEMS]);
194	  }
195	
196	  private persistLayout(items: ItemRect[]): void {
197	    for (const item of items) {
198	      this.sql.exec(
199	        `INSERT OR REPLACE INTO items (id, col, row, width, height) VALUES (?, ?, ?, ?, ?)`,
200	        item.id,
201	        item.column,
202	        item.row,
203	        item.width,
204	        item.height,
205	      );
206	    }
207	  }
208	}
