file.content:
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}

:root {
  --bg: #0D0D0F;
  --card: #1C1C1E;
  --text: #FFFFFF;
  --text-secondary: #AEAEB2;
  --text-tertiary: #8E8E93;
  --separator: rgba(255,255,255,0.10);
  --blue: #377DFF;
  --green: #30D158;
  --orange: #FF9F0A;
  --purple: #BF5AF2;
  --radius: 12px;
  --safe-bottom: env(safe-area-inset-bottom, 0px);
}

html {
  font-family: -apple-system, BlinkMacSystemFont, system-ui, sans-serif;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  min-height: 100dvh;
  padding-bottom: calc(72px + var(--safe-bottom));
}

.page-header {
  padding: calc(16px + env(safe-area-inset-top, 0px)) 20px 8px;
}

.page-title {
  font-size: 28px;
  font-weight: 700;
  letter-spacing: -0.3px;
}

.page-subtitle {
  font-size: 15px;
  color: var(--text-secondary);
  margin-top: 2px;
}

.page-main {
  padding: 8px 16px 24px;
}

/* ── Cards ── */
.card {
  background: var(--card);
  border-radius: var(--radius);
  padding: 16px;
  margin-bottom: 12px;
}

.card-label {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.6px;
  margin-bottom: 8px;
}

.card-title {
  font-size: 17px;
  font-weight: 600;
}

.card-subtitle {
  font-size: 14px;
  color: var(--text-secondary);
  margin-top: 2px;
}

.card-desc {
  font-size: 14px;
  color: var(--text-secondary);
  line-height: 1.45;
  margin-top: 8px;
}

/* ── Buttons ── */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  font-size: 15px;
  font-weight: 600;
  border: none;
  border-radius: 10px;
  padding: 10px 20px;
  min-height: 44px;
  cursor: pointer;
  text-decoration: none;
  transition: opacity 0.15s;
}
.btn:active { opacity: 0.7; }

.btn-blue, .btn-primary {
  background: var(--blue);
  color: #fff;
}

.btn-ghost {
  background: rgba(255,255,255,0.08);
  color: var(--text);
}

.btn-block {
  display: flex;
  width: 100%;
}

/* ── Stats row ── */
.stat-item {
  flex: 1;
  text-align: center;
  background: rgba(255,255,255,0.08);
  border-radius: 10px;
  padding: 10px 4px;
}

.stat-value {
  font-size: 20px;
  font-weight: 700;
  color: var(--blue);
}

.stat-label {
  font-size: 10px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.6px;
  color: var(--text-tertiary);
  margin-top: 2px;
}

/* ── Sections ── */
.section-header {
  font-size: 13px;
  font-weight: 600;
  color: var(--text-tertiary);
  text-transform: uppercase;
  letter-spacing: 0.6px;
  padding: 20px 4px 8px;
}

/* ── Section spacing ── */
.section-header + .card,
.section-header + .skill-card {
  margin-top: 0;
}

.card + .section-header,
.skill-card + .section-header {
  padding-top: 24px;
}

/* ── Tab bar ── */
.tab-bar {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  display: flex;
  justify-content: space-around;
  background: rgba(28,28,30,0.92);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-top: 1px solid var(--separator);
  padding: 8px 0 calc(8px + var(--safe-bottom));
  z-index: 100;
}

.tab-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
  text-decoration: none;
  color: var(--text-tertiary);
  font-size: 10px;
  font-weight: 500;
  padding: 4px 16px;
  transition: color 0.15s;
}

.tab-item.tab-active {
  color: var(--blue);
}

.tab-icon {
  width: 24px;
  height: 24px;
}

.tab-label {
  font-size: 10px;
}

/* ── Separators ── */
.separator {
  height: 1px;
  background: var(--separator);
  margin: 12px 0;
}

/* ── Completed items ── */
.completed-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 0;
  min-height: 44px;
}

.completed-item + .completed-item {
  border-top: 1px solid var(--separator);
}

.completed-title {
  font-size: 15px;
  color: var(--text-tertiary);
  text-decoration: line-through;
  flex: 1;
}

.completed-check {
  color: var(--green);
  font-size: 16px;
}

/* ── Upcoming list ── */
.upcoming-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 0;
  min-height: 44px;
}

.upcoming-item + .upcoming-item {
  border-top: 1px solid var(--separator);
}

.upcoming-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.upcoming-title {
  font-size: 15px;
  flex: 1;
}

.upcoming-count {
  font-size: 13px;
  color: var(--text-tertiary);
}

.upcoming-spacer .upcoming-title {
  color: var(--text-tertiary);
  font-style: italic;
}

/* ── Exercise list ── */
.exercise-item {
  padding: 14px 0;
}

.exercise-item + .exercise-item {
  border-top: 1px solid var(--separator);
}

.exercise-header {
  display: flex;
  align-items: baseline;
  gap: 8px;
}

.exercise-number {
  font-size: 13px;
  font-weight: 700;
  color: var(--text-tertiary);
  min-width: 20px;
}

.exercise-name {
  font-size: 16px;
  font-weight: 600;
  flex: 1;
}

.exercise-sets {
  font-size: 14px;
  font-weight: 600;
  color: var(--blue);
}

.exercise-notes {
  font-size: 14px;
  color: var(--text-secondary);
  line-height: 1.45;
  margin: 6px 0 0 28px;
}

.exercise-video {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 13px;
  color: var(--blue);
  text-decoration: none;
  margin: 6px 0 0 28px;
  min-height: 44px;
  padding: 4px 0;
}

.exercise-tags {
  display: flex;
  gap: 6px;
  margin: 6px 0 0 28px;
  flex-wrap: wrap;
}

.exercise-tag {
  font-size: 11px;
  font-weight: 600;
  color: var(--purple);
  background: rgba(191,90,242,0.12);
  padding: 2px 8px;
  border-radius: 6px;
}

/* ── Error card ── */
.error-card {
  background: rgba(255,159,10,0.08);
  border-radius: var(--radius);
  padding: 14px 16px;
  margin-bottom: 12px;
  display: flex;
  align-items: flex-start;
  gap: 10px;
}

.error-card-icon {
  font-size: 18px;
  flex-shrink: 0;
  line-height: 1;
}

.error-card-message {
  font-size: 14px;
  color: var(--orange);
  line-height: 1.45;
  flex: 1;
}

.error-card-dismiss {
  background: none;
  border: none;
  color: var(--text-tertiary);
  font-size: 18px;
  cursor: pointer;
  padding: 0;
  line-height: 1;
  flex-shrink: 0;
}

/* ── Phase coaching callout ── */
.coaching-callout {
  background: rgba(255,159,10,0.08);
  border-radius: var(--radius);
  padding: 14px 16px;
  margin-bottom: 16px;
}

.coaching-label {
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.6px;
  color: var(--orange);
  margin-bottom: 6px;
}

.coaching-focus {
  font-size: 14px;
  color: var(--text);
  line-height: 1.45;
}

.coaching-details {
  list-style: none;
  margin-top: 8px;
}

.coaching-details li {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.45;
  padding: 3px 0 3px 14px;
  position: relative;
}

.coaching-details li::before {
  content: "\2022";
  position: absolute;
  left: 0;
  color: var(--orange);
}

/* ── Back nav ── */
.back-nav {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  font-size: 15px;
  color: var(--blue);
  text-decoration: none;
  padding: 8px 0 12px;
}

/* ── Sticky footer ── */
.sticky-footer {
  position: sticky;
  bottom: calc(72px + var(--safe-bottom));
  padding: 24px 0 12px;
  background: linear-gradient(transparent, var(--bg) 12px);
  background-color: var(--bg);
}

/* ── Skill cards ── */
.skill-card {
  background: var(--card);
  border-radius: var(--radius);
  margin-bottom: 12px;
  overflow: hidden;
}

.skill-header {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px;
  cursor: pointer;
}

.skill-icon {
  font-size: 20px;
  width: 32px;
  height: 32px;
  display: flex;
  align-items: center;
  justify-content: center;
  border-radius: 8px;
  flex-shrink: 0;
}

.skill-name {
  font-size: 16px;
  font-weight: 600;
  flex: 1;
}

.skill-priority {
  font-size: 11px;
  font-weight: 700;
  color: var(--text-tertiary);
  background: rgba(255,255,255,0.06);
  padding: 2px 8px;
  border-radius: 6px;
}

.badge-green {
  display: inline-block;
  font-size: 12px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.6px;
  color: var(--green);
  background: rgba(48,209,88,0.1);
  padding: 4px 10px;
  border-radius: 6px;
  margin-top: 10px;
}

.skill-body {
  padding: 0 16px 16px;
  transition: opacity 0.15s ease;
}

.skill-timeline {
  font-size: 13px;
  color: var(--text-secondary);
  margin-bottom: 12px;
}

.milestone-list {
  list-style: none;
}

.milestone-item {
  display: flex;
  gap: 10px;
  padding: 8px 0;
}

.milestone-item + .milestone-item {
  border-top: 1px solid var(--separator);
}

.milestone-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  margin-top: 5px;
  flex-shrink: 0;
}

.milestone-name {
  font-size: 14px;
  font-weight: 600;
}

.milestone-desc {
  font-size: 13px;
  color: var(--text-secondary);
}

.milestone-week {
  font-size: 12px;
  color: var(--text-tertiary);
}

/* ── Roadmap ── */
.roadmap-item {
  display: flex;
  gap: 12px;
  padding: 14px 0;
}

.roadmap-item + .roadmap-item {
  border-top: 1px solid var(--separator);
}

.roadmap-indicator {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  margin-top: 4px;
  flex-shrink: 0;
}

.roadmap-name {
  font-size: 15px;
  font-weight: 600;
}

.roadmap-weeks {
  font-size: 13px;
  color: var(--text-secondary);
  margin-top: 2px;
}

.roadmap-summary {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.45;
  margin-top: 4px;
}

.roadmap-current .roadmap-name {
  color: var(--green);
}

/* ── Benchmarks ── */
.benchmark-item {
  padding: 14px 0;
}

.benchmark-item + .benchmark-item {
  border-top: 1px solid var(--separator);
}

.benchmark-name {
  font-size: 15px;
  font-weight: 600;
}

.benchmark-target {
  font-size: 13px;
  color: var(--blue);
  margin-top: 2px;
}

.benchmark-howto {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.45;
  margin-top: 4px;
}

/* ── Setup page ── */
.setup-container {
  max-width: 480px;
  margin: 0 auto;
}

.form-group {
  margin-bottom: 20px;
}

.form-label {
  display: block;
  font-size: 13px;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.6px;
  margin-bottom: 8px;
}

.form-input {
  width: 100%;
  padding: 12px 14px;
  font-size: 16px;
  font-family: inherit;
  background: var(--card);
  color: var(--text);
  border: 1px solid var(--separator);
  border-radius: var(--radius);
  outline: none;
  transition: border-color 0.15s;
}

.form-input:focus {
  border-color: var(--blue);
}

.template-grid {
  display: grid;
  gap: 12px;
}

.template-card {
  background: var(--card);
  border-radius: var(--radius);
  padding: 16px;
  cursor: pointer;
  transition: background 0.15s, box-shadow 0.15s;
  border: 1px solid transparent;
}

.template-card:hover {
  background: #2C2C2E;
}

.template-card:active {
  background: #3A3A3C;
}

.template-name {
  font-size: 16px;
  font-weight: 600;
}

.template-desc {
  font-size: 13px;
  color: var(--text-secondary);
  line-height: 1.4;
  margin-top: 4px;
}

/* ── Template card selection ── */
.template-card.selected {
  border-color: var(--blue);
  background: rgba(55,125,255,0.08);
}

/* ── Completed item structure ── */
.completed-header {
  display: flex;
  align-items: center;
  gap: 10px;
  flex: 1;
}

.workout-details {
  margin-top: 8px;
}

.workout-details summary {
  list-style: none;
}

.workout-details summary::-webkit-details-marker {
  display: none;
}

.workout-summary {
  font-size: 13px;
  color: var(--blue);
  cursor: pointer;
}

.workout-exercises {
  padding-top: 8px;
}

.workout-exercise {
  display: flex;
  align-items: baseline;
  gap: 8px;
  padding: 4px 0;
}

.workout-ex-name {
  font-size: 13px;
  color: var(--text-secondary);
  flex: 1;
}

.workout-ex-sets {
  font-size: 12px;
  color: var(--text-tertiary);
  white-space: nowrap;
}

/* ── Gate tests ── */
.gate-checklist {
  margin-top: 10px;
  font-size: 13px;
}

.gate-item {
  padding: 4px 0;
}

.gate-passed {
  color: var(--green);
}

.gate-not-passed {
  color: var(--orange);
}

.gate-all-passed {
  color: var(--green);
  font-weight: 600;
  margin-top: 8px;
  background: rgba(48,209,88,0.08);
  border-radius: 8px;
  padding: 8px 12px;
}

/* ── Skill assessments ── */
.skill-current-state {
  background: rgba(255,255,255,0.04);
  border-radius: 8px;
  padding: 10px 12px;
  margin-bottom: 12px;
}

.current-state-label {
  font-size: 11px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.6px;
  color: var(--text-tertiary);
  margin-bottom: 4px;
}

.current-state-text {
  font-size: 14px;
  color: var(--text-secondary);
  line-height: 1.45;
}

.skill-edit-row {
  margin-top: 8px;
  text-align: right;
}

.skill-edit-form {
  margin-top: 8px;
}

.skill-edit-actions {
  display: flex;
  gap: 8px;
  margin-top: 8px;
}

/* ── Benchmark details ── */
.benchmark-trend {
  font-size: 13px;
  color: var(--text-secondary);
  margin-top: 4px;
}

.benchmark-last-tested {
  font-size: 12px;
  color: var(--text-tertiary);
  margin-top: 4px;
}

.benchmark-retest {
  font-size: 12px;
  font-weight: 600;
  color: var(--orange);
  margin-top: 4px;
}

.benchmark-retest-info {
  font-size: 12px;
  color: var(--text-tertiary);
  margin-top: 4px;
}

